+type toonRobotEncoder struct {
+	w io.Writer
+}
+
+func (e *toonRobotEncoder) Encode(v any) error {
+	if !toon.Available() {
+		fmt.Fprintln(os.Stderr, "warning: tru not available; falling back to JSON")
+		return newJSONRobotEncoder(e.w).Encode(v)
+	}
+
