+	if err != nil {
+		return err
+	}
+
+	// json.Encoder.Encode always terminates with a newline; match that behavior for TOON.
+	out = strings.TrimRight(out, "\n")
+	_, err = io.WriteString(e.w, out+"\n")
+	return err
+}
